import 'dart:convert';

import 'package:ataulfo/features/messages/data/media/ogg_opus_duration.dart';
import 'package:flutter_test/flutter_test.dart';

/// Fixture REAL: ~3.0065s de Opus-en-Ogg producido por ffmpeg/libopus con la
/// config del grabador (opus, 16 kHz, mono, 16 kbps), embebido en base64. Es la
/// red contra "mi modelo del contenedor es incorrecto pero los fixtures
/// sintéticos codifican el mismo error": valida el parser contra la salida de un
/// encoder de verdad, sin depender de ffmpeg en CI. El parser resta el pre-skip,
/// así que devuelve la duración del CONTENIDO (~3000 ms), ~6 ms por debajo del
/// `format=duration` de ffprobe (3006 ms) — que es lo correcto para la barra.
const String _realOpus3sB64 =
    '';

void main() {
  test(
    'Opus/Ogg REAL de ffmpeg (~3s) -> ~3000ms (contenido, sin pre-skip)',
    () {
      final bytes = base64Decode(_realOpus3sB64);
      final ms = oggOpusDurationMs(bytes);
      expect(ms, isNotNull);
      expect((ms! - 3000).abs() <= 70, isTrue, reason: 'got $ms');
    },
  );
}
